	}

	return parts.length > 0 ? parts.join(" · ") : undefined;
}

function selectSessionIcon(card: SessionTreeCard): string {
	if (card.isStuck) {
		return "warning";
	}

	if (card.kind === "checkpoint" && card.status === "ENDED") {
		return "history";
	}

	return card.status === "ACTIVE" ? "pulse" : "clock";
