+
+function collectTranscriptTextParts(value: unknown): string[] {
+	if (typeof value === "string") {
+		return [value];
+	}
+
+	if (Array.isArray(value)) {
+		return value.flatMap((entry) => collectTranscriptTextParts(entry));
+	}
+
+	if (!isJsonObject(value)) {
+		return [];
+	}
+
+	const entryType = readString(value.type);
+	if (entryType === "tool_use") {
+		return [];
+	}
+
+	if (entryType === "text" && typeof value.text === "string") {
+		return [value.text];
+	}
+
+	if (entryType === "tool_result") {
+		return collectTranscriptTextParts(value.content);
+	}
+
+	if (typeof value.text === "string") {
+		return [value.text];
+	}
+
+	if (typeof value.content === "string") {
+		return [value.content];
+	}
+
+	return [];
+}
+
+function extractToolActivities(value: unknown): SessionDetailToolActivity[] {
+	if (!Array.isArray(value)) {
+		return [];
+	}
+
+	return value.flatMap((entry, index) => {
+		if (!isJsonObject(entry) || readString(entry.type) !== "tool_use") {
+			return [];
+		}
+
+		return [{
+			id: readString(entry.id) ?? `tool-${index}`,
+			kind: "tool_use" as const,
+			label: readString(entry.name) ?? "Tool",
+			detail: formatToolInput(entry.input),
+		} satisfies SessionDetailToolActivity];
+	});
+}
+
+function formatToolInput(value: unknown): string | undefined {
+	if (typeof value === "string") {
+		return value.trim() || undefined;
+	}
+
+	if (!isJsonObject(value)) {
+		return undefined;
+	}
+
+	const command = readString(value.command);
+	if (command) {
+		return command;
+	}
+
+	const path = readString(value.path);
+	const pattern = readString(value.pattern);
+	const description = readString(value.description);
+	const query = readString(value.query);
+	const search = readString(value.search_query);
+	const pieces = [
+		path ? `path: ${path}` : undefined,
+		pattern ? `pattern: ${pattern}` : undefined,
+		query ? `query: ${query}` : undefined,
+		search ? `search: ${search}` : undefined,
+		description,
+	].filter((piece): piece is string => typeof piece === "string" && piece.length > 0);
+	if (pieces.length > 0) {
+		return pieces.join(" · ");
+	}
