1399	function splitMessagePresentation(message: ParsedNativeTranscriptMessage): {
1400		primaryText?: string;
1401		auxiliaryBlocks: SessionDetailAuxiliaryBlock[];
1402	} {
1403		const rawEnvelope = asJsonObject(message.raw);
1404		const contentValue = resolveMessageContentValue(rawEnvelope);
1405		const auxiliaryBlocks = contentValue !== undefined
1406			? extractAuxiliaryBlocksFromContent(contentValue, message.id)
1407			: [];
1408		let primaryText = contentValue !== undefined
1409			? extractVisibleMessageText(contentValue)
1410			: message.content;
1411	
1412		if (message.author === "reasoning") {
1413			if (message.content) {
1414				auxiliaryBlocks.unshift(buildAuxiliaryBlock({
1415					id: `${message.id}-thinking`,
1416					kind: "thinking",
1417					label: "Thinking Process",
1418					detail: message.content,
1419					display: "text",
1420				}));
1421			}
1422			primaryText = undefined;
1423		}
1424	
1425		if (isToolOutputEnvelope(rawEnvelope)) {
1426			if (message.content) {
1427				auxiliaryBlocks.unshift(buildAuxiliaryBlock({
1428					id: `${message.id}-output`,
1429					kind: "output",
1430					label: inferToolOutputLabel(rawEnvelope),
1431					detail: message.content,
1432					display: "code",
1433					tone: inferToolOutputTone(rawEnvelope),
1434				}));
1435			}
1436			primaryText = undefined;
1437		}
1438	
1439		for (const activity of message.toolActivities) {
1440			if (auxiliaryBlocks.some((block) => block.id === activity.id || (block.kind === "tool_use" && block.label === activity.label && block.detail === activity.detail))) {
1441				continue;
1442			}
1443	
1444			auxiliaryBlocks.push(buildAuxiliaryBlock({
1445				id: activity.id,
1446				kind: "tool_use",
1447				label: activity.label,
1448				detail: activity.detail,
1449				display: "code",
1450			}));
1451		}
1452	
1453		if (!primaryText && auxiliaryBlocks.length === 0) {
1454			primaryText = message.content;
1455		}
1456	
1457		return {
1458			primaryText,
1459			auxiliaryBlocks,
1460		};
1461	}
