1463	function resolveMessageContentValue(rawEnvelope: JsonObject | undefined): unknown {
1464		if (!rawEnvelope) {
1465			return undefined;
1466		}
1467	
1468		const payload = asJsonObject(rawEnvelope.payload);
1469		const message = asJsonObject(rawEnvelope.message);
1470		return message?.content
1471			?? message?.text
1472			?? payload?.content
1473			?? payload?.output
1474			?? payload?.text
1475			?? rawEnvelope.content
1476			?? rawEnvelope.output
1477			?? rawEnvelope.text;
1478	}
