1480	function extractVisibleMessageText(value: unknown): string | undefined {
1481		const parts = collectVisibleMessageTextParts(value)
1482			.map((entry) => entry.trim())
1483			.filter((entry) => entry.length > 0);
1484		return parts.length > 0 ? parts.join("\n\n") : undefined;
1485	}
1486	
1487	function collectVisibleMessageTextParts(value: unknown): string[] {
1488		if (typeof value === "string") {
1489			return [value];
1490		}
1491	
1492		if (Array.isArray(value)) {
1493			return value.flatMap((entry) => collectVisibleMessageTextParts(entry));
1494		}
1495	
1496		if (!isJsonObject(value)) {
1497			return [];
1498		}
1499	
1500		const entryType = readString(value.type);
1501		if (entryType === "tool_use" || entryType === "tool_result" || entryType === "reasoning") {
1502			return [];
1503		}
1504		if ((entryType === "text" || entryType === "input_text" || entryType === "output_text")
1505			&& typeof value.text === "string") {
1506			return [value.text];
1507		}
1508		if (typeof value.text === "string") {
1509			return [value.text];
1510		}
1511		if (typeof value.content === "string") {
1512			return [value.content];
1513		}
1514		if (Array.isArray(value.content)) {
1515			return collectVisibleMessageTextParts(value.content);
1516		}
1517		return [];
1518	}
