1520	function extractAuxiliaryBlocksFromContent(value: unknown, idPrefix: string): SessionDetailAuxiliaryBlock[] {
1521		if (!Array.isArray(value)) {
1522			return [];
1523		}
1524	
1525		return value.flatMap((entry, index) => {
1526			if (!isJsonObject(entry)) {
1527				return [];
1528			}
1529	
1530			const entryType = readString(entry.type);
1531			if (entryType === "reasoning") {
1532				const detail = extractContentText(entry.text ?? entry.content);
1533				return detail
1534					? [buildAuxiliaryBlock({
1535						id: `${idPrefix}-thinking-${index}`,
1536						kind: "thinking",
1537						label: "Thinking Process",
1538						detail,
1539						display: "text",
1540					})]
1541					: [];
1542			}
1543	
1544			if (entryType === "tool_use") {
1545				return [buildAuxiliaryBlock({
1546					id: readString(entry.id) ?? `${idPrefix}-tool-${index}`,
1547					kind: "tool_use",
1548					label: readString(entry.name) ?? "Tool Execution",
1549					detail: formatToolDetail(entry.input),
1550					display: "code",
1551				})];
1552			}
1553	
1554			if (entryType === "tool_result") {
