1558						id: readString(entry.tool_use_id) ?? readString(entry.id) ?? `${idPrefix}-output-${index}`,
1559						kind: "output",
1560						label: "Tool Output",
1561						detail,
1562						display: "code",
1563						tone: entry.is_error === true ? "error" : "success",
1564					})]
1565					: [];
1566			}
1567	
1568			return [];
1569		});
1570	}
