		return parseFactoryTranscript;
	}
	if (looksLikeCursorTranscript(records)) {
		return parseCursorTranscript;
	}
	if (looksLikeClaudeTranscriptJsonl(records)) {
		return parseClaudeTranscript;
	}
	return parseGenericJsonlTranscript;
}

