	parserId: NativeTranscriptParserId;
	agentSlug: string;
	state: TranscriptBuildState;
	fallbackSessionId?: string;
	userHint?: string;
}): ParsedNativeTranscript | null {
	if (args.state.messages.length === 0) {
		return null;
	}

	const promptPreview = selectPromptPreview(args.state.messages);
	const title = args.state.title ?? promptPreview;
	const toolCount = args.state.messages.reduce((sum, message) => sum + message.toolActivities.length, 0);
	const turns = args.state.messages.map((message) => buildTurnFromMessage(message, args.agentSlug, args.state.model, args.userHint));

	return {
		parserId: args.parserId,
		agentSlug: args.agentSlug,
		sessionId: args.state.sessionId ?? args.fallbackSessionId,
		title,
		promptPreview,
		workspace: args.state.workspace,
		startedAt: args.state.startedAt,
		endedAt: args.state.endedAt,
		model: args.state.model,
		toolCount,
		metadata: args.state.metadata,
		messages: args.state.messages,
		turns,
	};
}

