function buildInitials(value: string): string {
	const parts = value
		.split(/[\s_-]+/g)
		.map((part) => part.trim())
		.filter((part) => part.length > 0);
	if (parts.length === 0) {
		return "AI";
	}
	if (parts.length === 1) {
		return parts[0].slice(0, 2).toUpperCase();
	}
	return parts
		.slice(0, 2)
		.map((part) => part[0]?.toUpperCase() ?? "")
